953→    void destroyPlaceholderMessages(LocalFolder localFolder, List<String> uids) throws MessagingException {
954→        for (String uid : uids) {
955→            LocalMessage placeholderMessage = localFolder.getMessage(uid);
956→            if (placeholderMessage == null) {
957→                continue;
958→            }
959→
960→            if (placeholderMessage.isSet(Flag.DELETED)) {
961→                placeholderMessage.destroy();
962→            } else {
963→                Timber.w("Expected local message %s in folder %s to be a placeholder, but DELETE flag wasn't set",
964→                        uid, localFolder.getServerId());
965→
966→                if (BuildConfig.DEBUG) {
967→                    throw new AssertionError("Placeholder message must have the DELETED flag set");
968→                }
969→            }
970→        }
971→    }
